package javacode.filehandling;

import java.io.File;
import java.io.FileInputStream;
import java.io.FileReader;
import java.io.IOException;
import java.util.Iterator;
import org.apache.poi.ss.usermodel.Cell;
import org.apache.poi.ss.usermodel.Row;
import org.apache.poi.xssf.usermodel.XSSFSheet;
import org.apache.poi.xssf.usermodel.XSSFWorkbook;

public class ReadTextFileExample {

	public static void main(String[] args) throws Exception {
		ReadTextFileExample obj = new ReadTextFileExample();

		// File txtfile = new File("./Files/SampleTextFile_10kb.txt");
		File xlsxfile = new File("./Files/BJS_Resume_Database.xlsx");
		// File docxfile = new File("./Files/SampleTextFile_10kb.txt");

		// obj.readtxtFile(txtfile);
		obj.readxlsxFile(xlsxfile);
		// obj.readdocxFile(docxfile);

	}

	public void readtxtFile(File file) throws IOException {

		FileReader fr = new FileReader(file);
		int i = 0;
		while ((i = fr.read()) != -1) {
			System.out.print((char) i);

		}
		fr.close();
	}

	public void readxlsxFile(File xlsxfile) throws Exception {

		FileInputStream fis = new FileInputStream(xlsxfile);

		// Finds the workbook instance for XLSX file
		XSSFWorkbook myWorkBook = new XSSFWorkbook(fis);

		// Return first sheet from the XLSX workbook
		XSSFSheet mySheet = myWorkBook.getSheetAt(0);

		// Get iterator to all the rows in current sheet
		Iterator<Row> rowIterator = mySheet.iterator();

		// Traversing over each row of XLSX file
		while (rowIterator.hasNext()) {
			Row row = rowIterator.next();
			// For each row, iterate through each columns
			Iterator<Cell> cellIterator = row.cellIterator();
			while (cellIterator.hasNext()) {
				Cell cell = cellIterator.next();

				switch (cell.getCellType()) {
				case Cell.CELL_TYPE_STRING:
					System.out.print(cell.getStringCellValue() + "\t");
					break;
				case Cell.CELL_TYPE_NUMERIC:
					System.out.print(cell.getNumericCellValue() + "\t");
					break;
				case Cell.CELL_TYPE_BOOLEAN:
					System.out.print(cell.getBooleanCellValue() + "\t");
					break;
				default:
				}
			}
			System.out.println("");
		}

	}

